"""Multi-start hexagonal packing for n=26 circles"""
import numpy as np

def construct_packing():
    n, best = 26, (None, None, 0)
    for r0 in np.linspace(0.07, 0.11, 10):
        for off in [0, r0/2]:
            c = init_grid(n, r0, off)
            c, r = refine(c, 30, 0.01)
            s = np.sum(r)
            if s > best[2]: best = (c.copy(), r.copy(), s)
    # Final refinement on best solution
    c, r = refine(best[0], 20, 0.008)
    return c, r, np.sum(r)

def init_grid(n, r, off):
    c = np.zeros((n, 2))
    dx, dy, i, row, y = 2*r, r*np.sqrt(3), 0, 0, r
    while i < n:
        x = r + (off if row % 2 else 0)
        while i < n and x < 1-r: c[i] = [x, y]; i += 1; x += dx
        y += dy; row += 1
    return np.clip(c, 0.01, 0.99)

def compute_r(c):
    n, r = len(c), np.zeros(len(c))
    for _ in range(50):
        for i in range(n):
            mx = min(c[i,0], c[i,1], 1-c[i,0], 1-c[i,1])
            for j in range(n):
                if i != j: mx = min(mx, max(0, np.linalg.norm(c[i]-c[j]) - r[j]))
            r[i] = mx
    return r

def refine(c, steps, step):
    c, r = c.copy(), compute_r(c)
    bc, br, bs = c.copy(), r.copy(), np.sum(r)
    dirs = [(1,0),(-1,0),(0,1),(0,-1),(.7,.7),(-.7,-.7),(.7,-.7),(-.7,.7)]
    for _ in range(steps):
        ok = False
        for i in range(len(c)):
            for dx, dy in dirs:
                nc = c.copy()
                nc[i] = np.clip(c[i] + step*np.array([dx,dy]), 0.01, 0.99)
                nr = compute_r(nc)
                if np.sum(nr) > bs + 1e-9:
                    bc, br, bs = nc.copy(), nr.copy(), np.sum(nr); ok = True
        if ok: c = bc.copy()
        step *= 0.94
    return bc, br
